// AGENT: Notification Engine v1.0.0 — PLACEHOLDER
// In Phase 6, this will:
//  1. Read user's notification_channels from preferences (email, slack, webhook)
//  2. For each channel: render notification template
//  3. Send via SMTP (email) / Slack webhook / HTTP webhook
//  4. INSERT into notifications table with status
//  5. Retry up to 3x on failure
//  6. Dedup: check notifications table to avoid duplicate sends

const input = $input.first().json;
const ctx   = input.execution_context;

// Tolerant: notification agent should never crash the pipeline
if (!ctx) {
  console.warn('[notification_engine] Missing execution_context — sending error notification with minimal data');
}

const started_at = Date.now();
console.log(`[notification_engine] START | execution_id=${ctx?.execution_id}`);

// Determine notification type
const isErrorNotification = input.error_type === 'pipeline_error';
const packets = ctx?.results?.application_packets || [];

// PLACEHOLDER: Log what would be sent
const notification_log = {
  notification_id:  `notif_placeholder_${Date.now()}`,
  user_id:          ctx?.user_id || 'unknown',
  execution_id:     ctx?.execution_id || 'unknown',
  type:             isErrorNotification ? 'pipeline_error' : 'pipeline_complete',
  channel:          'placeholder',
  subject:          isErrorNotification
    ? '⚠️ Job Search Pipeline Error'
    : `✅ Job Search Complete — ${packets.length} applications ready`,
  body:             isErrorNotification
    ? `Pipeline error: ${input.message || 'Unknown error'}`
    : `Your job search pipeline has completed. ${packets.length} application packets are ready for review.`,
  status:           'placeholder',
  sent_at:          null,
  note:             'PLACEHOLDER — Will send real notifications via SMTP/Slack/webhook in Phase 6'
};

console.log(`[notification_engine] COMPLETE (placeholder) | type=${notification_log.type}`);

return [{
  json: {
    execution_context: ctx,
    notification_log,
    notifications_sent: 0,
    status: 'placeholder',
    agent_meta: { agent_id: 'agent-notification-engine', agent_version: '1.0.0', execution_id: ctx?.execution_id, model_used: null, tokens_total: 0, duration_ms: Date.now() - started_at, status: 'placeholder', error: null }
  }
}];
